using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;

namespace SkFdc1.Models
{
    public class SensorDto
    {
        //null 대신 "의미있는 기본값을 가진 객체"를 반환해서 null 체크 자체를 없앰
        public string SensorID { get; set; } = string.Empty;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
        public string EquipID { get; set; } = string.Empty;
        public string SensorType { get; set; } = string.Empty;
        public string Unit { get; set; } = string.Empty;

        // "없음"을 표현하는 정적 빈 개게
        public static readonly SensorDto Empty = new SensorDto
        { 
            SensorID = "",
            EquipID = "",
            SensorType = "조회결과 없음",
            Unit = "-"
        };

        //빈 객체인지 확인하는 속성
        public bool IsEmpty => string.IsNullOrEmpty(SensorID);
    }
}
